"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[96483],{92483:(e,i,n)=>{n.r(i),n.d(i,{data:()=>s});const s={key:"v-4e00af10",path:"/leaflet/guide/Leaflet%E6%B8%B2%E6%9F%93%E5%99%A8%E4%B8%AD%E7%9A%84%E5%9B%BE%E5%B1%82%E9%98%9F%E5%88%97.html",title:"Leaflet渲染器中的图层队列",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1653445943e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"leaflet/guide/Leaflet渲染器中的图层队列.md"}},25602:(e,i,n)=>{n.r(i),n.d(i,{default:()=>l});const s=(0,n(57293).uE)('<p>[TOC]</p><h1 id="leaflet渲染器中的图层队列" tabindex="-1"><a class="header-anchor" href="#leaflet渲染器中的图层队列" aria-hidden="true">#</a> Leaflet渲染器中的图层队列</h1><p>在开始之前先简单介绍下渲染器。</p><p>渲染器是Leaflet中用于渲染显示矢量数据的。API自带的渲染器有以下3种：</p><ul><li>L.Renderer:渲染器的基类，不进行实例化</li><li>L.Canvas:使用Canvas渲染矢量数据</li><li>L.SVG:使用SVG渲染矢量数据</li></ul><p>渲染器中使用<code>_layers</code>字段存储图层对象。<code>key</code>值是<code>layer._leaflet_id</code>,<code>value</code>值是<code>layer</code></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202110291651236.png" alt="1630050027522"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202110291651238.png" alt="1630050130545"></p><p>使用<code>_drawLast</code>存储最后一个图层，使用<code>_drawFirst</code>指向第一个图层</p><p>每个添加到渲染器中的图层都会初始化一个_order对象</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>layer._order={\n\tlayer:layer,\n\tprev:this._drawLast,\n\tnext:null\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>layer:指向图层本身</li><li>prev:指向上一个order对象</li><li>next:指向下一个order对象</li></ul><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202110291651239.png" alt="image-20210827161815335"></p><p>当我们要遍历图层时</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>//从第一个一直next\nlet order=this._drawFirst;\nwhile(order)\n{\n\torder=order.next;\n}\n\n//从最后一个一直prev\nlet order=this._drawLast;\nwhile(order)\n{\n\torder=order.prev;        \n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当我们想从队列中删除某个图层</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>\t/**\n\t * 移除图层\n\t * \n\t * @param {L.Layer} layer\n\t */\n\t_removePath: function (layer) {\n\t\tvar order = layer._order;\n\t\tvar next = order.next;\n\t\tvar prev = order.prev;\n\n\t\t//不是最后一个\n\t\tif (next) {\n\t\t\tnext.prev = prev;\n\t\t} else {  //是最后一个\n\t\t\tthis._drawLast = prev;\n\t\t}\n\n\t\t//不是第一个\n\t\tif (prev) {\n\t\t\tprev.next = next;\n\t\t} else {  //是第一个\n\t\t\tthis._drawFirst = next;\n\t\t}\n\n\t\tdelete layer._order;\n\n\t\tdelete this._layers[Util.stamp(layer)];\n\t\t//重新渲染\n\t\tthis._requestRedraw(layer);\n\t}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>当我们想把图层排序为最后，渲染在最上面</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>_bringToFront: function (layer) {\n\t\tvar order = layer._order;\n\n\t\tif (!order) { return; }\n\n\t\tvar next = order.next;\n\t\tvar prev = order.prev;\n\n\t\tif (next) {\n\t\t\tnext.prev = prev;\n\t\t} else {\n\t\t\t// 已经是最后一个\n\t\t\treturn;\n\t\t}\n\t\tif (prev) {\n\t\t\tprev.next = next;\n\t\t} else if (next) {\n\t\t\t// Update first entry unless this is the\n\t\t\t// single entry\n\t\t\tthis._drawFirst = next;\n\t\t}\n\n\t\t//放到最后一个\n\t\torder.prev = this._drawLast;\n\t\tthis._drawLast.next = order;\n\n\t\torder.next = null;\n\t\tthis._drawLast = order;\n\n\t\tthis._requestRedraw(layer);\n\t},\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当我们想把图层排序为第一，渲染在最下面</p>',21),d={},l=(0,n(63243).Z)(d,[["render",function(e,i){return s}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,s]of i)n[e]=s;return n}}}]);